      "category_zh": "公告",
      "title_en": "<h2 class=\"blog-title\" style=\"overflow-wrap: break-word; color: rgb(0, 0, 0); font-family: Montserrat, sans-serif; font-size: 20px; font-weight: 500; white-space: normal; margin: 0px 0px 10px !important; line-height: 1.5 !important; border-width: medium !important; border-style: none !important; border-color: currentcolor !important; border-image: initial !important;\"><a class=\"blog-title-link blog-link\" href=\"http://www.ccc-wa.org/news/19cccwa\" style=\"text-decoration: none;\">第19期CCCWA“每周一星”: 移民资产处置问题 蔡律师事务所蔡清律师特邀嘉宾分享</a></h2>",
      "title_zh": "<h2 class=\"blog-title\" style=\"overflow-wrap: break-word; color: rgb(0, 0, 0); font-family: Montserrat, sans-serif; font-size: 20px; font-weight: 500; white-space: normal; margin: 0px 0px 10px !important; line-height: 1.5 !important; border-width: medium !important; border-style: none !important; border-color: currentcolor !important; border-image: initial !important;\"><a class=\"blog-title-link blog-link\" href=\"http://www.ccc-wa.org/news/19cccwa\" style=\"text-decoration: none;\">第19期CCCWA“每周一星”: 移民资产处置问题 蔡律师事务所蔡清律师特邀嘉宾分享</a></h2>",
      "date_en": "2020年8月24日",
      "date_zh": "2020年8月24日",
